    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    4,
    'Snow Sport Prep - 4w 3x/wk',
    'outdoor',
    3,
    60,
    ARRAY['Build cardiovascular endurance', 'Improve VO2 max', 'Improve athletic performance', 'Develop explosiveness']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Snow Sport Prep'
ON CONFLICT DO NOTHING;

